"""Render benchmark reports.

Two outputs:

  * Markdown (``retrieval_benchmark.md``) -- the human-readable artefact
    required by the assessment.
  * JSON (``retrieval_benchmark.json``) -- the structured comparison the
    assessment also accepts.
"""

from __future__ import annotations

import json
from pathlib import Path
from typing import Any

_MARKDOWN_INTRO = (
    "# Retrieval Benchmark: Strategy A (Raw) vs Strategy B (AI-Enhanced)\n\n"
    "Generated by `python -m rag.benchmarks`.\n\n"
    "* **Strategy A (Raw Vector Search)** -- embed the user query verbatim and run cosine top-k against the ChromaDB collection.\n"
    "* **Strategy B (AI-Enhanced Retrieval)** -- send the query through the mocked `vertexai.generative_models.GenerativeModel` (Gemini 1.5 Flash analogue) for rewriting/expansion, then embed and search.\n\n"
    "All vectors are produced by the mocked `vertexai.language_models.TextEmbeddingModel` "
    "(`textembedding-gecko@003`), routed locally to `sentence-transformers/all-MiniLM-L6-v2`.\n"
)


def write_reports(report: dict[str, Any], md_path: str | Path, json_path: str | Path) -> None:
    md_path = Path(md_path)
    json_path = Path(json_path)
    md_path.parent.mkdir(parents=True, exist_ok=True)
    json_path.parent.mkdir(parents=True, exist_ok=True)

    md_path.write_text(_render_markdown(report), encoding="utf-8")
    json_path.write_text(json.dumps(report, indent=2, ensure_ascii=False), encoding="utf-8")


def _render_markdown(report: dict[str, Any]) -> str:
    top_k = report["top_k"]
    summary = report["summary"]
    comparisons = report["comparisons"]

    sections: list[str] = [_MARKDOWN_INTRO, "## Summary\n"]
    sections.append(_render_summary_table(summary, top_k))
    sections.append("\n## Per-query comparison\n")
    for index, entry in enumerate(comparisons, start=1):
        sections.append(_render_comparison(index, entry, top_k))
    return "\n".join(sections)


def _render_summary_table(summary: dict[str, Any], top_k: int) -> str:
    lines = [
        f"| Metric @ k={top_k} | Strategy A (Raw) | Strategy B (Expanded) | Delta (B - A) |",
        "|---|---:|---:|---:|",
    ]
    for metric in ("precision_at_k", "recall_at_k", "mrr"):
        raw_val = summary["raw"][metric]
        exp_val = summary["expanded"][metric]
        lines.append(
            f"| {metric.replace('_', ' ')} | {raw_val:.3f} | {exp_val:.3f} | {exp_val - raw_val:+.3f} |"
        )
    raw_lat = summary["raw"]["avg_latency_ms"]
    exp_lat = summary["expanded"]["avg_latency_ms"]
    lines.append(f"| avg latency (ms) | {raw_lat:.1f} | {exp_lat:.1f} | {exp_lat - raw_lat:+.1f} |")
    lines.append(
        f"\nAverage top-{top_k} document overlap between strategies: "
        f"**{summary['average_overlap_at_k']:.2f}** "
        "(lower means the strategies surfaced different documents)."
    )
    return "\n".join(lines)


def _render_comparison(index: int, entry: dict[str, Any], top_k: int) -> str:
    relevant = ", ".join(entry.get("relevant_doc_ids", [])) or "_(none provided)_"
    expansion = entry["expanded"].get("expansion") or {}
    expansion_md = (
        f"- LLM model: `{expansion.get('model', 'n/a')}`\n"
        f"- Original: `{expansion.get('original', '')}`\n"
        f"- Rewrite: `{expansion.get('expanded', '')}`\n"
        if expansion
        else ""
    )
    return (
        f"### {index}. Query: {entry['query']}\n\n"
        f"Relevant document IDs (gold): {relevant}\n\n"
        f"#### Query expansion (Strategy B)\n{expansion_md}\n"
        f"#### Strategy A -- Raw Vector Search (top {top_k})\n"
        f"{_render_hits_table(entry['raw'])}\n\n"
        f"#### Strategy B -- AI-Enhanced (top {top_k})\n"
        f"{_render_hits_table(entry['expanded'])}\n\n"
        f"#### Metrics\n{_render_metrics_table(entry, top_k)}\n"
    )


def _render_hits_table(side: dict[str, Any]) -> str:
    lines = [
        "| Rank | Doc ID | Score | Chunk preview |",
        "|---:|---|---:|---|",
    ]
    for rank, hit in enumerate(side["hits"], start=1):
        preview = hit["text"].replace("\n", " ")
        if len(preview) > 140:
            preview = preview[:137] + "..."
        lines.append(f"| {rank} | {hit['doc_id']} | {hit['score']:.4f} | {preview} |")
    return "\n".join(lines)


def _render_metrics_table(entry: dict[str, Any], top_k: int) -> str:
    raw_metrics = entry["raw"]["metrics"]
    exp_metrics = entry["expanded"]["metrics"]
    lines = [
        f"| Metric @ k={top_k} | A (Raw) | B (Expanded) |",
        "|---|---:|---:|",
        f"| precision@k | {raw_metrics['precision_at_k']:.3f} | {exp_metrics['precision_at_k']:.3f} |",
        f"| recall@k    | {raw_metrics['recall_at_k']:.3f} | {exp_metrics['recall_at_k']:.3f} |",
        f"| MRR         | {raw_metrics['mrr']:.3f} | {exp_metrics['mrr']:.3f} |",
        f"| latency (ms)| {entry['raw']['latency_ms']:.1f} | {entry['expanded']['latency_ms']:.1f} |",
        f"| overlap@k   | {entry['overlap_at_k']:.2f} | -- |",
    ]
    return "\n".join(lines)


__all__ = ["write_reports"]
